using ContosoUniversity.Services;
using ContosoUniversity.Models;

namespace ContosoUniversity.Tests.Services;

public class NotificationServiceTests : IDisposable
{
    private readonly NotificationService _service;

    public NotificationServiceTests()
    {
        _service = new NotificationService();
        // Drain static queue to avoid cross-test contamination
        while (_service.ReceiveNotification() != null) { }
    }

    public void Dispose()
    {
        // Drain queue after test
        while (_service.ReceiveNotification() != null) { }
        _service.Dispose();
    }

    [Fact]
    public void SendNotification_WithDisplayName_CreatesCorrectMessage()
    {
        _service.SendNotification("Student", "1", "Carson Alexander", EntityOperation.CREATE, "Admin");

        var notification = _service.ReceiveNotification();

        Assert.NotNull(notification);
        Assert.Equal("Student", notification.EntityType);
        Assert.Equal("1", notification.EntityId);
        Assert.Equal("CREATE", notification.Operation);
        Assert.Equal("New Student 'Carson Alexander' has been created", notification.Message);
        Assert.Equal("Admin", notification.CreatedBy);
        Assert.False(notification.IsRead);
    }

    [Fact]
    public void SendNotification_WithoutDisplayName_UsesIdInMessage()
    {
        _service.SendNotification("Course", "42", EntityOperation.UPDATE);

        var notification = _service.ReceiveNotification();

        Assert.NotNull(notification);
        Assert.Equal("Course (ID: 42) has been updated", notification.Message);
        Assert.Equal("System", notification.CreatedBy);
    }

    [Fact]
    public void SendNotification_Delete_CreatesDeleteMessage()
    {
        _service.SendNotification("Department", "5", "Mathematics", EntityOperation.DELETE, "Teacher");

        var notification = _service.ReceiveNotification();

        Assert.NotNull(notification);
        Assert.Equal("Department 'Mathematics' has been deleted", notification.Message);
        Assert.Equal("DELETE", notification.Operation);
    }

    [Fact]
    public void SendNotification_WithNullUserName_DefaultsToSystem()
    {
        _service.SendNotification("Student", "1", EntityOperation.CREATE, null);

        var notification = _service.ReceiveNotification();

        Assert.NotNull(notification);
        Assert.Equal("System", notification.CreatedBy);
    }

    [Fact]
    public void SendNotification_SetsCreatedAtToNow()
    {
        var before = DateTime.Now.AddSeconds(-1);
        _service.SendNotification("Student", "1", EntityOperation.CREATE);
        var after = DateTime.Now.AddSeconds(1);

        var notification = _service.ReceiveNotification();

        Assert.NotNull(notification);
        Assert.InRange(notification.CreatedAt, before, after);
    }

    [Fact]
    public void ReceiveNotification_EmptyQueue_ReturnsNull()
    {
        var result = _service.ReceiveNotification();

        Assert.Null(result);
    }

    [Fact]
    public void ReceiveNotification_DequeuseInFIFOOrder()
    {
        _service.SendNotification("Student", "1", EntityOperation.CREATE);
        _service.SendNotification("Course", "2", EntityOperation.UPDATE);
        _service.SendNotification("Department", "3", EntityOperation.DELETE);

        var first = _service.ReceiveNotification();
        var second = _service.ReceiveNotification();
        var third = _service.ReceiveNotification();
        var fourth = _service.ReceiveNotification();

        Assert.Equal("Student", first!.EntityType);
        Assert.Equal("Course", second!.EntityType);
        Assert.Equal("Department", third!.EntityType);
        Assert.Null(fourth);
    }

    [Fact]
    public void SendNotification_QueueCapEnforced()
    {
        // Send more than 500 notifications to test cap
        for (int i = 0; i < 510; i++)
        {
            _service.SendNotification("Entity", i.ToString(), EntityOperation.CREATE);
        }

        // Count remaining items
        int count = 0;
        while (_service.ReceiveNotification() != null)
            count++;

        Assert.True(count <= 500, $"Queue should be capped at 500 but had {count} items");
    }

    [Fact]
    public void MarkAsRead_DoesNotThrow()
    {
        // MarkAsRead is a no-op, just verify it doesn't throw
        var exception = Record.Exception(() => _service.MarkAsRead(1));
        Assert.Null(exception);
    }

    [Fact]
    public void MarkAsRead_WithAnyId_DoesNotThrow()
    {
        var exception = Record.Exception(() => _service.MarkAsRead(999));
        Assert.Null(exception);
    }

    [Fact]
    public void Dispose_DoesNotThrow()
    {
        var service = new NotificationService();
        var exception = Record.Exception(() => service.Dispose());
        Assert.Null(exception);
    }

    [Fact]
    public void SendNotification_WithEmptyDisplayName_UsesIdInMessage()
    {
        _service.SendNotification("Student", "1", "", EntityOperation.CREATE);

        var notification = _service.ReceiveNotification();

        Assert.NotNull(notification);
        Assert.Equal("New Student (ID: 1) has been created", notification.Message);
    }

    [Fact]
    public void SendNotification_WithWhitespaceDisplayName_UsesIdInMessage()
    {
        _service.SendNotification("Student", "1", "   ", EntityOperation.CREATE);

        var notification = _service.ReceiveNotification();

        Assert.NotNull(notification);
        Assert.Equal("New Student (ID: 1) has been created", notification.Message);
    }

    [Theory]
    [InlineData(EntityOperation.CREATE, "New Student (ID: 1) has been created")]
    [InlineData(EntityOperation.UPDATE, "Student (ID: 1) has been updated")]
    [InlineData(EntityOperation.DELETE, "Student (ID: 1) has been deleted")]
    public void SendNotification_AllOperations_GenerateCorrectMessages(EntityOperation operation, string expectedMessage)
    {
        _service.SendNotification("Student", "1", operation);

        var notification = _service.ReceiveNotification();

        Assert.NotNull(notification);
        Assert.Equal(expectedMessage, notification.Message);
    }
}

namespace ContosoUniversity.Tests.Utilities;

public class PaginatedListTests
{
    [Fact]
    public void Constructor_SetsPageIndexAndTotalPages()
    {
        var items = new List<string> { "a", "b", "c" };

        var list = new PaginatedList<string>(items, 10, 2, 3);

        Assert.Equal(2, list.PageIndex);
        Assert.Equal(4, list.TotalPages); // ceil(10/3) = 4
        Assert.Equal(3, list.Count);
    }

    [Fact]
    public void HasPreviousPage_FirstPage_ReturnsFalse()
    {
        var list = new PaginatedList<int>(new List<int> { 1 }, 10, 1, 5);

        Assert.False(list.HasPreviousPage);
    }

    [Fact]
    public void HasPreviousPage_SecondPage_ReturnsTrue()
    {
        var list = new PaginatedList<int>(new List<int> { 1 }, 10, 2, 5);

        Assert.True(list.HasPreviousPage);
    }

    [Fact]
    public void HasNextPage_LastPage_ReturnsFalse()
    {
        var list = new PaginatedList<int>(new List<int> { 1 }, 10, 2, 5);

        Assert.False(list.HasNextPage); // TotalPages = ceil(10/5) = 2, PageIndex = 2
    }

    [Fact]
    public void HasNextPage_FirstPageOfMany_ReturnsTrue()
    {
        var list = new PaginatedList<int>(new List<int> { 1 }, 10, 1, 5);

        Assert.True(list.HasNextPage);
    }

    [Fact]
    public void Create_SinglePage_ReturnsAllItems()
    {
        var source = new List<int> { 1, 2, 3 }.AsQueryable();

        var result = PaginatedList<int>.Create(source, 1, 10);

        Assert.Equal(3, result.Count);
        Assert.Equal(1, result.PageIndex);
        Assert.Equal(1, result.TotalPages);
        Assert.False(result.HasPreviousPage);
        Assert.False(result.HasNextPage);
    }

    [Fact]
    public void Create_MultiplePages_FirstPage()
    {
        var source = Enumerable.Range(1, 25).AsQueryable();

        var result = PaginatedList<int>.Create(source, 1, 10);

        Assert.Equal(10, result.Count);
        Assert.Equal(1, result.PageIndex);
        Assert.Equal(3, result.TotalPages);
        Assert.False(result.HasPreviousPage);
        Assert.True(result.HasNextPage);
        Assert.Equal(1, result[0]);
        Assert.Equal(10, result[9]);
    }

    [Fact]
    public void Create_MultiplePages_MiddlePage()
    {
        var source = Enumerable.Range(1, 25).AsQueryable();

        var result = PaginatedList<int>.Create(source, 2, 10);

        Assert.Equal(10, result.Count);
        Assert.Equal(2, result.PageIndex);
        Assert.True(result.HasPreviousPage);
        Assert.True(result.HasNextPage);
        Assert.Equal(11, result[0]);
        Assert.Equal(20, result[9]);
    }

    [Fact]
    public void Create_MultiplePages_LastPage()
    {
        var source = Enumerable.Range(1, 25).AsQueryable();

        var result = PaginatedList<int>.Create(source, 3, 10);

        Assert.Equal(5, result.Count);
        Assert.Equal(3, result.PageIndex);
        Assert.True(result.HasPreviousPage);
        Assert.False(result.HasNextPage);
        Assert.Equal(21, result[0]);
        Assert.Equal(25, result[4]);
    }

    [Fact]
    public void Create_EmptySource_ReturnsEmptyList()
    {
        var source = new List<int>().AsQueryable();

        var result = PaginatedList<int>.Create(source, 1, 10);

        Assert.Empty(result);
        Assert.Equal(1, result.PageIndex);
        Assert.Equal(0, result.TotalPages);
        Assert.False(result.HasPreviousPage);
        Assert.False(result.HasNextPage);
    }

    [Fact]
    public void Create_ExactlyOnePageSize()
    {
        var source = Enumerable.Range(1, 10).AsQueryable();

        var result = PaginatedList<int>.Create(source, 1, 10);

        Assert.Equal(10, result.Count);
        Assert.Equal(1, result.TotalPages);
        Assert.False(result.HasPreviousPage);
        Assert.False(result.HasNextPage);
    }

    [Fact]
    public void Create_PageSizeOne()
    {
        var source = Enumerable.Range(1, 5).AsQueryable();

        var result = PaginatedList<int>.Create(source, 3, 1);

        Assert.Single(result);
        Assert.Equal(3, result[0]);
        Assert.Equal(5, result.TotalPages);
        Assert.True(result.HasPreviousPage);
        Assert.True(result.HasNextPage);
    }
}

