using ContosoUniversity.Controllers;
using ContosoUniversity.Data;
using ContosoUniversity.Models;
using ContosoUniversity.Services;
using ContosoUniversity.Tests.Helpers;
using Microsoft.AspNetCore.Mvc;

namespace ContosoUniversity.Tests.Controllers;

public class NotificationsControllerTests : IDisposable
{
    // Drain static queue before and after tests
    public NotificationsControllerTests()
    {
        DrainQueue();
    }

    public void Dispose()
    {
        DrainQueue();
    }

    private static void DrainQueue()
    {
        var svc = new NotificationService();
        while (svc.ReceiveNotification() != null) { }
    }

    [Fact]
    public void GetNotifications_EmptyQueue_ReturnsEmptyNotifications()
    {
        using var context = TestDbContextFactory.Create();
        var controller = new NotificationsController(context);

        var result = controller.GetNotifications();

        Assert.IsType<JsonResult>(result);
        var value = result.Value;
        Assert.NotNull(value);
        // Use reflection to check the anonymous type
        var successProp = value.GetType().GetProperty("success");
        Assert.NotNull(successProp);
        Assert.True((bool)successProp!.GetValue(value)!);
        var countProp = value.GetType().GetProperty("count");
        Assert.Equal(0, (int)countProp!.GetValue(value)!);
    }

    [Fact]
    public void GetNotifications_WithItems_ReturnsNotifications()
    {
        using var context = TestDbContextFactory.Create();
        // Enqueue some notifications using the static queue
        var svc = new NotificationService();
        svc.SendNotification("Student", "1", "Test Student", EntityOperation.CREATE, "Admin");
        svc.SendNotification("Course", "2", "Test Course", EntityOperation.UPDATE, "Admin");

        var controller = new NotificationsController(context);

        var result = controller.GetNotifications();

        var value = result.Value!;
        var countProp = value.GetType().GetProperty("count");
        Assert.Equal(2, (int)countProp!.GetValue(value)!);
    }

    [Fact]
    public void GetNotifications_MoreThan10_LimitsTo10()
    {
        using var context = TestDbContextFactory.Create();
        var svc = new NotificationService();
        for (int i = 0; i < 15; i++)
        {
            svc.SendNotification("Entity", i.ToString(), EntityOperation.CREATE);
        }

        var controller = new NotificationsController(context);
        var result = controller.GetNotifications();

        var value = result.Value!;
        var countProp = value.GetType().GetProperty("count");
        Assert.Equal(10, (int)countProp!.GetValue(value)!);
    }

    [Fact]
    public void MarkAsRead_ReturnsSuccess()
    {
        using var context = TestDbContextFactory.Create();
        var controller = new NotificationsController(context);

        var result = controller.MarkAsRead(1);

        Assert.IsType<JsonResult>(result);
        var value = result.Value!;
        var successProp = value.GetType().GetProperty("success");
        Assert.True((bool)successProp!.GetValue(value)!);
    }

    [Fact]
    public void Index_ReturnsViewResult()
    {
        using var context = TestDbContextFactory.Create();
        var controller = new NotificationsController(context);

        var result = controller.Index();

        Assert.IsType<ViewResult>(result);
    }
}

